/// <summary>
/// Coroutine kullanım örnekleri — zamanlama, tekrar, sıralı eylemler.
/// </summary>
public class CoroutineExamples : MonoBehaviour
{
    [Header("Ayarlar")]
    [SerializeField] private float fireRate = 0.5f;
    [SerializeField] private float fadeDuration = 1f;

    // WaitForSeconds cache — her yield'da new yapmayı önler (GC tasarrufu)
    private WaitForSeconds _fireWait;

    private Coroutine _fireCoroutine;

    private void Awake()
    {
        _fireWait = new WaitForSeconds(fireRate);
    }

    // ─── 1. Basit Gecikme ────────────────────────────────────
    public void SpawnAfterDelay(float delay)
    {
        StartCoroutine(SpawnRoutine(delay));
    }

    private IEnumerator SpawnRoutine(float delay)
    {
        yield return new WaitForSeconds(delay);
        Debug.Log("Düşman spawn edildi!");
    }

    // ─── 2. Tekrarlayan Ateş (Başlat / Durdur) ──────────────
    public void StartFiring()
    {
        // Önceki coroutine varsa durdur (çift çalışma engeli)
        if (_fireCoroutine != null)
            StopCoroutine(_fireCoroutine);

        _fireCoroutine = StartCoroutine(FireRoutine());
    }

    public void StopFiring()
    {
        if (_fireCoroutine != null)
        {
            StopCoroutine(_fireCoroutine);
            _fireCoroutine = null;
        }
    }

    private IEnumerator FireRoutine()
    {
        while (true) // Sonsuz döngü — StopCoroutine ile durur
        {
            Debug.Log("Ateş!");
            yield return _fireWait; // Cache'lenmiş bekleme
        }
    }

    // ─── 3. Fade Out (Her Frame Alpha Değiştir) ──────────────
    public void FadeOut(CanvasGroup canvasGroup)
    {
        StartCoroutine(FadeRoutine(canvasGroup, 1f, 0f));
    }

    private IEnumerator FadeRoutine(CanvasGroup cg, float from, float to)
    {
        float elapsed = 0f;
        while (elapsed < fadeDuration)
        {
            elapsed += Time.deltaTime;
            cg.alpha = Mathf.Lerp(from, to, elapsed / fadeDuration);
            yield return null; // Bir sonraki frame'e geç
        }
        cg.alpha = to;
    }
}

