/// <summary>
/// Raycast kullanım örnekleri — silah, tıklama, zemin algılama.
/// </summary>
public class RaycastExamples : MonoBehaviour
{
    [Header("Silah Ayarları")]
    [SerializeField] private float weaponRange = 50f;
    [SerializeField] private int weaponDamage = 25;
    [SerializeField] private LayerMask hitLayers; // Inspector'dan seç

    [Header("Zemin Kontrolü")]
    [SerializeField] private float groundCheckDist = 1.1f;
    [SerializeField] private LayerMask groundLayer;

    private Camera _mainCam;

    private void Awake()
    {
        _mainCam = Camera.main; // Cache — her frame Camera.main çağırma
    }

    // ─── 1. FPS Silah Atışı ──────────────────────────────────
    public void Shoot()
    {
        Ray ray = new Ray(transform.position, transform.forward);

        if (Physics.Raycast(ray, out RaycastHit hit, weaponRange, hitLayers))
        {
            Debug.Log($"İsabet: {hit.collider.name} (mesafe: {hit.distance:F1}m)");

            // Hasar ver
            if (hit.collider.TryGetComponent<IDamageable>(out var target))
                target.TakeDamage(weaponDamage);

            // İsabet noktasında efekt
            Debug.DrawLine(ray.origin, hit.point, Color.red, 0.5f);
        }
        else
        {
            // Bir şeye isabet etmedi
            Debug.DrawRay(ray.origin, ray.direction * weaponRange, Color.yellow, 0.5f);
        }
    }

    // ─── 2. Mouse Tıklama ile Nesne Seçme ────────────────────
    private void Update()
    {
        if (Input.GetMouseButtonDown(0))
        {
            Ray ray = _mainCam.ScreenPointToRay(Input.mousePosition);

            if (Physics.Raycast(ray, out RaycastHit hit, 100f))
            {
                Debug.Log($"Tıklanan: {hit.collider.name}");
            }
        }
    }

    // ─── 3. Yerde mi Kontrolü (IsGrounded) ───────────────────
    public bool IsGrounded()
    {
        return Physics.Raycast(
            transform.position,
            Vector3.down,
            groundCheckDist,
            groundLayer
        );
    }
}

