/// <summary>
/// Profesyonel zıplama sistemi.
/// Ground Check + Coyote Time + Jump Buffer + Fall Multiplier.
/// </summary>
[RequireComponent(typeof(Rigidbody))]
public class JumpSystem : MonoBehaviour
{
    [Header("Zıplama")]
    [SerializeField] private float jumpForce = 12f;
    [SerializeField] private LayerMask groundLayer;
    [SerializeField] private Transform groundCheck;
    [SerializeField] private float groundCheckRadius = 0.2f;

    [Header("Game Feel")]
    [SerializeField] private float coyoteTime = 0.15f;
    [SerializeField] private float jumpBufferTime = 0.15f;
    [SerializeField] private float fallMultiplier = 2.5f;
    [SerializeField] private float lowJumpMultiplier = 2f;

    private Rigidbody _rb;
    private float _coyoteTimer;
    private float _jumpBufferTimer;
    private bool _isGrounded;

    private void Awake()
    {
        _rb = GetComponent<Rigidbody>();
    }

    private void Update()
    {
        // ── Ground Check (OverlapSphere) ─────────────────────
        _isGrounded = Physics.CheckSphere(
            groundCheck.position,
            groundCheckRadius,
            groundLayer
        );

        // ── Coyote Time ──────────────────────────────────────
        if (_isGrounded)
            _coyoteTimer = coyoteTime;
        else
            _coyoteTimer -= Time.deltaTime;

        // ── Jump Buffer ──────────────────────────────────────
        if (Input.GetButtonDown("Jump"))
            _jumpBufferTimer = jumpBufferTime;
        else
            _jumpBufferTimer -= Time.deltaTime;

        // ── Zıplama Koşulu ───────────────────────────────────
        if (_jumpBufferTimer > 0f && _coyoteTimer > 0f)
        {
            _rb.linearVelocity = new Vector3(
                _rb.linearVelocity.x,
                jumpForce,
                _rb.linearVelocity.z
            );
            _coyoteTimer = 0f;
            _jumpBufferTimer = 0f;
        }
    }

    private void FixedUpdate()
    {
        // ── Geliştirilmiş Yerçekimi (Game Feel) ──────────────
        if (_rb.linearVelocity.y < 0f)
        {
            // Düşerken daha hızlı çek (ağır his)
            _rb.linearVelocity += Vector3.up * Physics.gravity.y * (fallMultiplier - 1f) * Time.fixedDeltaTime;
        }
        else if (_rb.linearVelocity.y > 0f && !Input.GetButton("Jump"))
        {
            // Tuşu erken bırakırsa kısa zıplama
            _rb.linearVelocity += Vector3.up * Physics.gravity.y * (lowJumpMultiplier - 1f) * Time.fixedDeltaTime;
        }
    }

    // Debug: Ground check alanını sahnede göster
    private void OnDrawGizmosSelected()
    {
        if (groundCheck == null) return;
        Gizmos.color = Color.green;
        Gizmos.DrawWireSphere(groundCheck.position, groundCheckRadius);
    }
}

